mapper.select:
select kb.id as id, ct.sw_id as swId, kb.title as title, ct.name as categoryName, user.real_name as userName, kb.pub_time as createTime, kb.status AS status, kb.dept_id as deptId, kb.remark as remark, kb.cover as cover, case when t2.num is null then 0 else t2.num end as readCount from kb_video kb join kb_category ct on ct.id = kb.category_id join castle_sys_user user on user.id = kb.auth left join (select b_id, count(1) num from kb_basic_user t where t.type = 1 group by b_id) t2 on t2.b_id = kb.id where kb.is_deleted = 2 and ct.is_deleted = 2 and ct.sw_id=#{kbVideoShowDto.swId}
AND kb.title like concat('%',#{kbVideoShowDto.title},'%')
AND kb.dept_id = #{kbVideoShowDto.deptId}
AND user.real_name like concat('%', #{kbVideoShowDto.userName},'%')
AND kb.status = #{kbVideoShowDto.status}
AND (kb.pub_time >= #{kbVideoShowDto.fromTime } and kb.pub_time <= #{kbVideoShowDto.endTime})
and ct.id in (
#{categoryId}
)
order by kb.pub_time ASC
order by kb.pub_time DESC
order by CAST( readCount AS UNSIGNED) DESC
order by CAST( readCount AS UNSIGNED) ASC
limit #{map.offset},#{map.rows}

select count(1) from kb_video kb join kb_category ct on ct.id = kb.category_id join castle_sys_user user on user.id = kb.auth left join (select b_id, count(1) num from kb_basic_user t where t.type = 1 group by b_id) t2 on t2.b_id = kb.id where kb.is_deleted = 2 and ct.is_deleted = 2 and ct.sw_id=#{kbVideoShowDto.swId}
AND kb.title like concat('%',#{kbVideoShowDto.title},'%')
AND kb.dept_id = #{kbVideoShowDto.deptId}
AND user.real_name like concat('%', #{kbVideoShowDto.userName},'%')
AND kb.status = #{kbVideoShowDto.status}
AND (kb.pub_time >= #{kbVideoShowDto.fromTime } and kb.pub_time <= #{kbVideoShowDto.endTime})
and ct.id in (
#{categoryId}
)

select distinct * from (select kb.id as id, ct.sw_id as swId, kb.title as title, ct.name as categoryName, user.real_name as userName, kb.pub_time as createTime, kb.status AS status, kb.dept_id as deptId, kb.remark as remark, kb.cover as cover, case when t2.num is null then 0 else t2.num end as readCount from kb_video kb join kb_category ct on ct.id = kb.category_id join kb_warehouse_auth au on ((ct.id = au.wh_id and au.category = 01 and au.status = 1) or (ct.id = au.wh_id and au.category = 01 and au.status = 2) or (ct.id = au.wh_id and au.category = 01 and au.status = 3) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 1) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 2) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 3)) left join kb_groups_user groupu on groupu.group_id = au.user_id left join (select dept.id,user.id uid,dept.parents from castle_sys_dept dept join castle_sys_user user on user.dept_id=dept.id) dept on (dept.id = au.user_id or dept.parents like concat('%', au.user_id, '%')) join castle_sys_user user on kb.auth = user.id left join (select b_id, count(1) num from kb_basic_user t where t.type = 1 group by b_id) t2 on t2.b_id = kb.id where kb.is_deleted = 2 and au.is_deleted = 2 and ct.is_deleted = 2 and (kb.exp_time >= now() or kb.exp_time is null) and (au.user_id =#{uid} or groupu.user_id=#{uid} or dept.uid=#{uid}) and ((kb.status in(1,2) and kb.auth=#{uid}) or kb.status=1 ) and ct.sw_id=#{kbVideoShowDto.swId} and au.kb_auth in (
#{kb_auth}
)
AND kb.title like concat('%',#{kbVideoShowDto.title},'%')
AND ct.id = #{kbVideoShowDto.authId}
AND kb.dept_id = #{kbVideoShowDto.deptId}
AND user.real_name like concat('%', #{kbVideoShowDto.userName},'%')
AND kb.status = #{kbVideoShowDto.status}
AND (kb.pub_time >= #{kbVideoShowDto.fromTime } and kb.pub_time <= #{kbVideoShowDto.endTime})
and ct.id in (
#{categoryId}
)
union select distinct kb.id as id, ct.sw_id as swId, kb.title as title, ct.name as categoryName, user.real_name as userName, kb.pub_time as createTime, kb.status AS status, kb.dept_id as deptId, kb.remark as remark, kb.cover as cover, case when t2.num is null then 0 else t2.num end as readCount from kb_video kb join kb_category ct on ct.id = kb.category_id join kb_warehouse_auth au on ((ct.id = au.wh_id and au.category = 01 and au.status = 1) or (ct.id = au.wh_id and au.category = 01 and au.status = 2) or (ct.id = au.wh_id and au.category = 01 and au.status = 3) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 1) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 2) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 3)) left join kb_groups_user groupu on groupu.group_id = au.user_id left join castle_sys_dept dept on (dept.id = au.user_id or dept.parents like concat('%',au.user_id,'%')) join castle_sys_user user on (user.id = kb.auth and au.user_id = user.id or (user.id = groupu.user_id and user.id = kb.auth) or (user.dept_id = dept.id and user.id = kb.auth)) left join (select b_id, count(1) num from kb_basic_user t where t.type = 1 group by b_id) t2 on t2.b_id = kb.id where kb.is_deleted = 2 and au.is_deleted = 2 and ct.is_deleted = 2 and user.id=#{uid} and ct.sw_id=#{kbVideoShowDto.swId} and ((kb.status in(1,2) and kb.auth=#{uid}) or kb.status=1 ) and au.kb_auth =3
AND kb.title like concat('%',#{kbVideoShowDto.title},'%')
AND ct.id = #{kbVideoShowDto.authId}
AND kb.dept_id = #{kbVideoShowDto.deptId}
AND user.real_name like concat('%', #{kbVideoShowDto.userName},'%')
AND kb.status = #{kbVideoShowDto.status}
AND (kb.pub_time >= #{kbVideoShowDto.fromTime } and kb.pub_time <= #{kbVideoShowDto.endTime})
and ct.id in (
#{categoryId}
)
) t
order by t.createTime ASC
order by t.createTime DESC
order by CAST( readCount AS UNSIGNED) DESC
order by CAST( readCount AS UNSIGNED) ASC
limit #{map.offset},#{map.rows}

select count(distinct t.id) from (select kb.id as id, ct.sw_id as swId, kb.title as title, ct.name as categoryName, user.real_name as userName, kb.pub_time as createTime, ct.status AS status, kb.dept_id as deptId, kb.remark as remark, kb.cover as cover, case when t2.num is null then 0 else t2.num end as readCount from kb_video kb join kb_category ct on ct.id = kb.category_id join kb_warehouse_auth au on ((ct.id = au.wh_id and au.category = 01 and au.status = 1) or (ct.id = au.wh_id and au.category = 01 and au.status = 2) or (ct.id = au.wh_id and au.category = 01 and au.status = 3) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 1) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 2) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 3)) left join kb_groups_user groupu on groupu.group_id = au.user_id left join (select dept.id,user.id uid,dept.parents from castle_sys_dept dept join castle_sys_user user on user.dept_id=dept.id) dept on (dept.id = au.user_id or dept.parents like concat('%', au.user_id, '%')) join castle_sys_user user on kb.auth = user.id left join (select b_id, count(1) num from kb_basic_user t where t.type = 1 group by b_id) t2 on t2.b_id = kb.id where kb.is_deleted = 2 and au.is_deleted = 2 and ct.is_deleted = 2 and (kb.exp_time >= now() or kb.exp_time is null) and (au.user_id =#{uid} or groupu.user_id=#{uid} or dept.uid=#{uid}) and ((kb.status in(1,2) and kb.auth=#{uid}) or kb.status=1 ) and ct.sw_id=#{kbVideoShowDto.swId} and au.kb_auth in (
#{kb_auth}
)
AND kb.title like concat('%',#{kbVideoShowDto.title},'%')
AND ct.id = #{kbVideoShowDto.authId}
AND kb.dept_id = #{kbVideoShowDto.deptId}
AND user.real_name like concat('%', #{kbVideoShowDto.userName},'%')
AND kb.status = #{kbVideoShowDto.status}
AND (kb.pub_time >= #{kbVideoShowDto.fromTime } and kb.pub_time <= #{kbVideoShowDto.endTime})
and ct.id in (
#{categoryId}
)
union select distinct kb.id as id, ct.sw_id as swId, kb.title as title, ct.name as categoryName, user.real_name as userName, kb.pub_time as createTime, ct.status AS status, kb.dept_id as deptId, kb.remark as remark, kb.cover as cover, case when t2.num is null then 0 else t2.num end as readCount from kb_video kb join kb_category ct on ct.id = kb.category_id join kb_warehouse_auth au on ((ct.id = au.wh_id and au.category = 01 and au.status = 1) or (ct.id = au.wh_id and au.category = 01 and au.status = 2) or (ct.id = au.wh_id and au.category = 01 and au.status = 3) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 1) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 2) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 3)) left join kb_groups_user groupu on groupu.group_id = au.user_id left join castle_sys_dept dept on (dept.id = au.user_id or dept.parents like concat('%',au.user_id,'%')) join castle_sys_user user on (user.id = kb.auth and au.user_id = user.id or (user.id = groupu.user_id and user.id = kb.auth) or (user.dept_id = dept.id and user.id = kb.auth)) left join (select b_id, count(1) num from kb_basic_user t where t.type = 1 group by b_id) t2 on t2.b_id = kb.id where kb.is_deleted = 2 and au.is_deleted = 2 and ct.is_deleted = 2 and user.id=#{uid} and ct.sw_id=#{kbVideoShowDto.swId} and ((kb.status in(1,2) and kb.auth=#{uid}) or kb.status=1 ) and au.kb_auth =3
AND kb.title like concat('%',#{kbVideoShowDto.title},'%')
AND ct.id = #{kbVideoShowDto.authId}
AND kb.dept_id = #{kbVideoShowDto.deptId}
AND user.real_name like concat('%', #{kbVideoShowDto.userName},'%')
AND kb.status = #{kbVideoShowDto.status}
AND (kb.pub_time >= #{kbVideoShowDto.fromTime } and kb.pub_time <= #{kbVideoShowDto.endTime})
and ct.id in (
#{categoryId}
)
) t

select distinct vi.*, user.real_name as userName, ct.name as cateName, vi.dept_id as deptId from kb_video vi join kb_category ct on ct.id = vi.category_id join kb_warehouse_auth au on ((ct.id = au.wh_id and au.category = 01 and au.status = 1) or (ct.id = au.wh_id and au.category = 01 and au.status = 2) or (ct.id = au.wh_id and au.category = 01 and au.status = 3) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 1) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 2) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 3)) left join kb_groups_user groupu on groupu.group_id = au.user_id left join (select dept.id,user.id uid,dept.parents from castle_sys_dept dept join castle_sys_user user on user.dept_id=dept.id) dept on (dept.id = au.user_id or dept.parents like concat('%', au.user_id, '%')) join castle_sys_user user on vi.auth = user.id where vi.is_deleted = 2 and au.is_deleted = 2 and ct.is_deleted = 2 and vi.id =#{vid} and (au.user_id = #{uid} or groupu.user_id = #{uid} or dept.uid = #{uid}) and au.kb_auth in (
#{kb_auth}
)

select distinct * from (select video.*, readCount,ct.sw_id as swId from kb_video video left join (select count(1) readCount, b_id from kb_basic_user where type = 1 group by 2) bu on video.id = bu.b_id join kb_category ct on ct.id = video.category_id join kb_warehouse_auth au on ((ct.id = au.wh_id and au.category = 01 and au.status = 1) or (ct.id = au.wh_id and au.category = 01 and au.status = 2) or (ct.id = au.wh_id and au.category = 01 and au.status = 3) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 1) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 2) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 3)) left join kb_groups_user groupu on groupu.group_id = au.user_id left join castle_sys_dept dept on (dept.id = au.user_id or dept.parents like concat('%',au.user_id,'%')) left join castle_sys_user user on user.dept_id = dept.id where (au.user_id = #{uid} or groupu.user_id = #{uid} or user.id = #{uid}) and (video.exp_time >=now() or video.exp_time is null) and video.is_deleted = 2 and ((video.status in(1) and video.auth=#{uid}) or video.status=1 )
and video.category_id =#{swId}
and au.kb_auth in (
#{kb_auth}
)
union select video.*, readCount,ct.sw_id as swId from kb_video video left join (select count(1) readCount, b_id from kb_basic_user where type = 1 group by 2) bu on video.id = bu.b_id join kb_category ct on ct.id = video.category_id join kb_subject_warehouse sw on sw.id = ct.sw_id join kb_warehouse_auth au on ((ct.id = au.wh_id and au.category = 01 and au.status = 1) or (ct.id = au.wh_id and au.category = 01 and au.status = 2) or (ct.id = au.wh_id and au.category = 01 and au.status = 3) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 1) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 2) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 3)) left join kb_groups_user groupu on groupu.group_id = au.user_id left join castle_sys_dept dept on (dept.id = au.user_id or dept.parents like concat('%',au.user_id,'%')) left join castle_sys_user user on (user.id = video.auth and au.user_id = user.id or (user.id = groupu.user_id and user.id = video.auth) or (user.dept_id = dept.id and user.id = video.auth)) where user.id = #{uid} and au.kb_auth = 3 and video.is_deleted = 2 and ((video.status in(1,2) and video.auth=#{uid}) or video.status=1 ) and (video.exp_time >=now() or video.exp_time is null)
and video.category_id =#{swId}
)t order by t.readCount desc ,t.pub_time desc limit 4

select distinct t.* from (select kb.*,user.real_name authName ,ct.sw_id as swId from kb_video kb join kb_category ct on ct.id = kb.category_id join kb_warehouse_auth au on ((ct.id = au.wh_id and au.category = 01 and au.status = 1) or (ct.id = au.wh_id and au.category = 01 and au.status = 2) or (ct.id = au.wh_id and au.category = 01 and au.status = 3) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 1) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 2) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 3)) left join kb_groups_user groupu on groupu.group_id = au.user_id left join (select dept.id,user.id uid,dept.parents from castle_sys_dept dept join castle_sys_user user on user.dept_id=dept.id) dept on (dept.id = au.user_id or dept.parents like concat('%', au.user_id, '%')) join castle_sys_user user on kb.auth = user.id where kb.is_deleted = 2 and kb.status = 1 and au.is_deleted = 2 and ct.is_deleted = 2 and (kb.exp_time >= now() or kb.exp_time is null) and (au.user_id =#{uid} or groupu.user_id=#{uid} or dept.uid=#{uid}) and au.kb_auth in (
#{kb_auth}
) union select kb.*,user.real_name createName ,ct.sw_id as swId from kb_video kb join kb_category ct on ct.id = kb.category_id join kb_warehouse_auth au on ((ct.id = au.wh_id and au.category = 01 and au.status = 1) or (ct.id = au.wh_id and au.category = 01 and au.status = 2) or (ct.id = au.wh_id and au.category = 01 and au.status = 3) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 1) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 2) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 3)) left join kb_groups_user groupu on groupu.group_id = au.user_id left join castle_sys_dept dept on (dept.id = au.user_id or dept.parents like concat('%',au.user_id,'%')) join castle_sys_user user on (user.id = kb.auth and au.user_id = user.id or (user.id = groupu.user_id and user.id = kb.auth) or (user.dept_id = dept.id and user.id = kb.auth)) where kb.is_deleted = 2 and au.is_deleted = 2 and ct.is_deleted = 2 and user.id=#{uid} and kb.status=1 and au.kb_auth =3 ) t order by rand() limit 5
